COMMENT ON TABLE assessment.qti_packages IS 'An imported assessment bundle containing QTI XML, resources, media, metadata, and a manifest.';
COMMENT ON COLUMN assessment.qti_packages.id IS 'The platform''s stable ID for this QTI package.';
